func solve(m: Int64, n: Int64, waitCost: Array<Array<Int64>>) -> Int64 {
    let rows = Int(m)
    let cols = Int(n)
    guard rows > 0 && cols > 0 else { return 0 }

    // We'll use a priority queue (min-heap) to explore states in order of increasing total cost
    // Each state is (totalCost, time, i, j)
    var heap = Heap<(Int64, Int64, Int, Int)> { $0.0 < $1.0 }
    heap.insert((0, 1, 0, 0))

    // Visited dictionary to keep track of the minimal cost for each (time % 2, i, j)
    // Key: (time % 2, i, j), Value: minimal cost
    var visited = [String: Int64]()

    let directions = [(0, 1), (1, 0)] // right, down

    while !heap.isEmpty {
        let (currentCost, currentTime, i, j) = heap.remove()!

        if i == rows - 1 && j == cols - 1 {
            return currentCost
        }

        let key = "\(currentTime % 2),\(i),\(j)"
        if let existingCost = visited[key], existingCost <= currentCost {
            continue
        }
        visited[key] = currentCost

        if currentTime % 2 == 1 {
            // Odd time: move right or down
            for (di, dj) in directions {
                let ni = i + di
                let nj = j + dj
                if ni < rows && nj < cols {
                    let enterCost = Int64(ni + 1) * Int64(nj + 1)
                    let newCost = currentCost + enterCost
                    let newTime = currentTime + 1
                    heap.insert((newCost, newTime, ni, nj))
                }
            }
        } else {
            // Even time: wait
            let waitCostHere = waitCost[i][j]
            let newCost = currentCost + waitCostHere
            let newTime = currentTime + 1
            heap.insert((newCost, newTime, i, j))
        }
    }

    return -1 // should not reach here for valid inputs
}

// Helper Heap (Priority Queue) implementation
struct Heap<T> {
    private var elements = [T]()
    private let priorityFunction: (T, T) -> Bool

    var isEmpty: Bool {
        return elements.isEmpty
    }

    init(priorityFunction: @escaping (T, T) -> Bool) {
        self.priorityFunction = priorityFunction
    }

    mutating func insert(_ value: T) {
        elements.append(value)
        swim(elements.count - 1)
    }

    mutating func remove() -> T? {
        guard !elements.isEmpty else { return nil }
        if elements.count == 1 {
            return elements.removeLast()
        }
        elements.swapAt(0, elements.count - 1)
        let value = elements.removeLast()
        sink(0)
        return value
    }

    private mutating func swim(_ index: Int) {
        var childIndex = index
        var parentIndex = (childIndex - 1) / 2
        while childIndex > 0 && priorityFunction(elements[childIndex], elements[parentIndex]) {
            elements.swapAt(childIndex, parentIndex)
            childIndex = parentIndex
            parentIndex = (childIndex - 1) / 2
        }
    }

    private mutating func sink(_ index: Int) {
        var parentIndex = index
        while true {
            let leftChildIndex = 2 * parentIndex + 1
            let rightChildIndex = 2 * parentIndex + 2
            var candidateIndex = parentIndex
            if leftChildIndex < elements.count && priorityFunction(elements[leftChildIndex], elements[candidateIndex]) {
                candidateIndex = leftChildIndex
            }
            if rightChildIndex < elements.count && priorityFunction(elements[rightChildIndex], elements[candidateIndex]) {
                candidateIndex = rightChildIndex
            }
            if candidateIndex == parentIndex {
                return
            }
            elements.swapAt(parentIndex, candidateIndex)
            parentIndex = candidateIndex
        }
    }
}
