            for (dr, dc) in directions {
                let newRow = row + dr
                let newCol = col + dc
                if newRow < rows && newCol < cols {
                    let newStep = step + 1
                    let moveCost = Int64((newRow + 1) * (newCol + 1))
                    let newCost = currentCost + moveCost
                    if newCost < visited[newStep % 2][newRow][newCol] {
                        visited[newStep % 2][newRow][newCol] = newCost
                        heap.insert((newCost, newStep, newRow, newCol))
                    }
