            let newStep = step + 1
            let waitCostCurrent = waitCost[row][col]
            let newCost = currentCost + waitCostCurrent
            if newCost < visited[newStep % 2][row][col] {
                visited[newStep % 2][row][col] = newCost
                heap.insert((newCost, newStep, row, col))
