    dp[0][0][0][0] = entryCost

    var q = Deque<(Int64, Int64, Int64, Int64)>()
    q.push_back((0, 0, 0, 0))

    while !q.empty() {
        let (i, j, time, state) = q.front()
        q.pop_front()

        let current_cost = dp[Int(i)][Int(j)][Int(state)][Int(time % 2)]

        if i == rows - 1 && j == cols - 1 {
            continue
        }

        if time % 2 == 0 {
            // Even step - must wait
            let new_time = time + 1
            let new_state = state
            let wait_cost = waitCost[Int(i)][Int(j)]
            let total_cost = current_cost + wait_cost

            if total_cost < dp[Int(i)][Int(j)][Int(new_state)][Int(new_time % 2)] {
                dp[Int(i)][Int(j)][Int(new_state)][Int(new_time % 2)] = total_cost
                q.push_back((i, j, new_time, new_state))
            }
        } else {
            // Odd step - must move
            for (di, dj) in dirs {
                let ni = i + di
                let nj = j + dj

                if ni >= 0 && ni < rows && nj >= 0 && nj < cols {
                    let new_time = time + 1
                    let new_state = (state + 1) % 2
                    let move_cost = (ni + 1) * (nj + 1)
                    let total_cost = current_cost + move_cost

                    if total_cost < dp[Int(ni)][Int(nj)][Int(new_state)][Int(new_time % 2)] {
                        dp[Int(ni)][Int(nj)][Int(new_state)][Int(new_time % 2)] = total_cost
                        q.push_back((ni, nj, new_time, new_state))
                    }
                }
            }
        }
    }

    var min_cost = inf
    for state in 0..<2 {
        for parity in 0..<2 {
            let cost = dp[Int(rows - 1)][Int(cols - 1)][state][parity]
            if cost < min_cost {
                min_cost = cost
            }
        }
    }

    return min_cost
}
