import Foundation

func solve(m: Int64, n: Int64, waitCost: Array<Array<Int64>>) -> Int64 {
    let mInt = Int(m)
    let nInt = Int(n)
    let rows = mInt
    let cols = nInt

    // We need to track the minimal cost for each cell (i,j) at step k (odd or even)
    // Since steps alternate between odd and even, we can represent state as (i,j, isOddStep)
    // Initialize DP table with infinity
    var dp = Array(repeating: Array(repeating: Array(repeating: Int64.max, count: 2), count: cols), count: rows)

    // Starting at (0,0) at step 1 (odd)
    dp[0][0][1] = (0 + 1) * (0 + 1)  // entry cost

    // Priority queue for Dijkstra's algorithm: (cost, i, j, isOddStep)
    var heap = Heap<(Int64, Int, Int, Int)>(sort: { $0.0 < $1.0 })
    heap.insert((dp[0][0][1], 0, 0, 1))

    let directions = [(0, 1), (1, 0)] // right, down

    while !heap.isEmpty {
        let (currentCost, i, j, isOddStep) = heap.remove()!

        if i == rows - 1 && j == cols - 1 {
            return currentCost
        }

        if currentCost > dp[i][j][isOddStep] {
            continue
        }

        if isOddStep == 1 {
            // Current step is odd, must move
            for (di, dj) in directions {
                let ni = i + di
                let nj = j + dj
                if ni < rows && nj < cols {
                    let entryCost = (ni + 1) * (nj + 1)
                    let newCost = currentCost + entryCost
                    let newStep = 0 // next step is even
                    if newCost < dp[ni][nj][newStep] {
                        dp[ni][nj][newStep] = newCost
                        heap.insert((newCost, ni, nj, newStep))
                    }
                }
            }
        } else {
            // Current step is even, must wait
            let waitCostHere = waitCost[i][j]
            let newCost = currentCost + waitCostHere
            let newStep = 1 // next step is odd
            if newCost < dp[i][j][newStep] {
                dp[i][j][newStep] = newCost
                heap.insert((newCost, i, j, newStep))
            }
        }
    }

    return -1 // should not reach here if path exists
}

// Heap implementation for Dijkstra's algorithm
struct Heap<T> {
    private var elements: [T]
    private let sort: (T, T) -> Bool

    init(sort: @escaping (T, T) -> Bool) {
        self.elements = []
        self.sort = sort
    }

    var isEmpty: Bool {
        return elements.isEmpty
    }

    mutating func insert(_ value: T) {
        elements.append(value)
        siftUp(from: elements.count - 1)
    }

    mutating func remove() -> T? {
        guard !elements.isEmpty else { return nil }
        if elements.count == 1 {
            return elements.removeLast()
        } else {
            let value = elements[0]
            elements[0] = elements.removeLast()
            siftDown(from: 0)
            return value
        }
    }

    private mutating func siftUp(from index: Int) {
        var child = index
        var parent = parentIndex(of: child)
        while child > 0 && sort(elements[child], elements[parent]) {
            elements.swapAt(child, parent)
            child = parent
            parent = parentIndex(of: child)
        }
    }

    private mutating func siftDown(from index: Int) {
        var parent = index
        while true {
            let left = leftChildIndex(of: parent)
            let right = rightChildIndex(of: parent)
            var candidate = parent
            if left < elements.count && sort(elements[left], elements[candidate]) {
                candidate = left
            }
            if right < elements.count && sort(elements[right], elements[candidate]) {
                candidate = right
            }
            if candidate == parent {
                return
            }
            elements.swapAt(parent, candidate)
            parent = candidate
        }
    }

    private func parentIndex(of index: Int) -> Int {
        return (index - 1) / 2
    }

    private func leftChildIndex(of index: Int) -> Int {
        return 2 * index + 1
    }

    private func rightChildIndex(of index: Int) -> Int {
        return 2 * index + 2
    }
}
