            for (di, dj) in directions {
                let ni = i + di
                let nj = j + dj
                if ni < rows and nj < cols {
                    let cost = dp[i][j][time_mod] + (ni + 1) * (nj + 1)
                    if cost < dp[ni][nj][(time_mod + 1) % 2] {
