import Foundation

func solve(m: Int64, n: Int64, waitCost: Array<Array<Int64>>) -> Int64 {
    let mInt = Int(m)
    let nInt = Int(n)
    var dp = [[[Int64]]](repeating: [[Int64]](repeating: [Int64.max, Int64.max], count: nInt), count: mInt)
    dp[0][0][0] = (0 + 1) * (0 + 1) // initial entry cost

    var queue = [(row: Int, col: Int, step: Int)]()
    queue.append((0, 0, 1))

    let directions = [(1, 0), (0, 1)] // down and right

    while !queue.isEmpty {
        let current = queue.removeFirst()
        let row = current.row
        let col = current.col
        let step = current.step

        if step % 2 == 1 {
            // Odd step: move
            for dir in directions {
                let newRow = row + dir.0
                let newCol = col + dir.1
                if newRow < mInt && newCol < nInt {
                    let cost = (newRow + 1) * (newCol + 1)
                    let newTotal = dp[row][col][(step - 1) % 2] + cost
                    if newTotal < dp[newRow][newCol][step % 2] {
                        dp[newRow][newCol][step % 2] = newTotal
                        queue.append((newRow, newCol, step + 1))
                    }
                }
            }
        } else {
            // Even step: wait
            let waitCostCurrent = waitCost[row][col]
            let newTotal = dp[row][col][(step - 1) % 2] + waitCostCurrent
            if newTotal < dp[row][col][step % 2] {
                dp[row][col][step % 2] = newTotal
                queue.append((row, col, step + 1))
            }
        }
    }

    return min(dp[mInt - 1][nInt - 1][0], dp[mInt - 1][nInt - 1][1])
}
