import "std"

func solve(m: Int64, n: Int64, waitCost: Array<Array<Int64>>): Int64 {
    let rows = m
    let cols = n
    let inf = 1 << 60

    // dp[i][j][k] represents the minimal cost to reach (i,j) at step k (0: odd, 1: even)
    var dp = Array(repeating: Array(repeating: Array(repeating: inf, count: 2), count: cols), count: rows)

    // Initial state: step 1 (odd) at (0,0)
    dp[0][0][0] = (0 + 1) * (0 + 1)

    for step in 1..<(2 * rows * cols) {
        for i in 0..<rows {
            for j in 0..<cols {
                for k in 0..<2 {
                    if dp[i][j][k] == inf {
                        continue
                    }
                    if k == 0 {
                        // Current step is odd (move)
                        // Try moving right
                        if j + 1 < cols {
                            let new_i = i
                            let new_j = j + 1
                            let cost = (new_i + 1) * (new_j + 1)
                            if dp[new_i][new_j][1] > dp[i][j][k] + cost {
                                dp[new_i][new_j][1] = dp[i][j][k] + cost
                            }
                        }
                        // Try moving down
                        if i + 1 < rows {
                            let new_i = i + 1
                            let new_j = j
                            let cost = (new_i + 1) * (new_j + 1)
                            if dp[new_i][new_j][1] > dp[i][j][k] + cost {
                                dp[new_i][new_j][1] = dp[i][j][k] + cost
                            }
                        }
                    } else {
                        // Current step is even (wait)
                        let cost = waitCost[i][j]
                        if dp[i][j][0] > dp[i][j][k] + cost {
                            dp[i][j][0] = dp[i][j][k] + cost
                        }
                    }
                }
            }
        }
    }

    let result = min(dp[rows - 1][cols - 1][0], dp[rows - 1][cols - 1][1])
    return result
}
